use std::fmt::{self, Display};
use std::fs;
use std::path::PathBuf;

#[derive(Debug)]
enum BuildError {
    MissingFile(PathBuf),
    CompilationFailed(String),
}

impl Display for BuildError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            BuildError::MissingFile(path) => write!(f, "Input file missing: {}", path.display()),
            BuildError::CompilationFailed(reason) => write!(f, "Compilation failed due to: {}", reason),
        }
    }
}

impl std::error::Error for BuildError {}

struct DependencyGraph {
    dependencies: Vec<PathBuf>,
}

impl DependencyGraph {
    fn new(paths: Vec<PathBuf>) -> Self {
        DependencyGraph { dependencies: paths }
    }

    fn check_and_build(&self) -> Result<(), BuildError> {
        for path in &self.dependencies {
            if !path.exists() {
                return Err(BuildError::MissingFile(path.clone()));
            }
            match self.attempt_compile(path) {
                Ok(_) => println!("Successfully processed: {}", path.display()),
                Err(e) => return Err(e),
            }
        }
        Ok(())
    }

    fn attempt_compile(&self, path: &PathBuf) -> Result<(), BuildError> {
        let content = fs::read_to_string(path).unwrap_or_default();
        if content.is_empty() {
            return Err(BuildError::CompilationFailed("File is empty".to_string()));
        }
        Ok(())
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let temp_dir = PathBuf::from("temp_build_root");
    if !temp_dir.exists() {
        fs::create_dir(&temp_dir)?;
    }

    let good_file = temp_dir.join("main.rs");
    fs::write(&good_file, "fn main(){}")?;

    let bad_input_path = temp_dir.join("missing.txt");
    let graph = DependencyGraph::new(vec![good_file.clone(), bad_input_path.clone()]);

    match graph.check_and_build() {
        Ok(_) => println!("Build system finished successfully."),
        Err(e) => eprintln!("Build failed: {}", e),
    }

    fs::remove_dir(&temp_dir)?;
    Ok(())
}

use std::fmt::{self, Display};
use std::path::PathBuf;

#[derive(Debug)]
enum ConfigError {
    Io(std::io::Error),
    NotFound(PathBuf),
    InvalidFormat(&'static str),
}

impl From<std::io::Error> for ConfigError {
    fn from(err: std::io::Error) -> Self {
        ConfigError::Io(err)
    }
}

impl Display for ConfigError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            ConfigError::Io(err) => write!(f, "File system error occurred: {}", err),
            ConfigError::NotFound(path) => write!(f, "Required configuration file not found at path: {}", path.display()),
            ConfigError::InvalidFormat(msg) => write!(f, "Configuration validation failed: {}", msg),
        }
    }
}

impl std::error::Error for ConfigError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            ConfigError::Io(err) => Some(err),
            _ => None,
        }
    }
}

fn load_config(path: &PathBuf) -> Result<(), ConfigError> {
    if !path.exists() {
        return Err(ConfigError::NotFound(path.clone()));
    }
    println!("Successfully checked file existence for {}", path.display());
    Ok(())
}

fn main() {
    let good_path = PathBuf::from("config.toml");
    let bad_path = PathBuf::from("/nonexistent/settings.yml");

    match load_config(&good_path) {
        Ok(_) => println!("Configuration loaded successfully."),
        Err(e) => eprintln!("Error loading config: {}", e),
    }

    match load_config(&bad_path) {
        Ok(_) => (),
        Err(e) => eprintln!("Caught expected error for bad path: {}", e),
    }
}

