use std::collections::HashMap;

#[derive(Debug)]
pub enum DataLoadError {
    NotFound(String),
    InvalidInput(String),
    ServiceFailure(String),
}

impl std::fmt::Display for DataLoadError {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        match self {
            DataLoadError::NotFound(s) => write!(f, "Resource not found: {}", s),
            DataLoadError::InvalidInput(s) => write!(f, "Bad data provided: {}", s),
            DataLoadError::ServiceFailure(s) => write!(f, "Internal service error: {}", s),
        }
    }
}

impl std::error::Error for DataLoadError {} 

pub fn process_data(key: &str, data: &HashMap<String, String>) -> Result<(), Box<dyn std::error::Error>> {
    if key.is_empty() {
        return Err(Box::new(DataLoadError::InvalidInput("Key cannot be empty".to_string())));
    }

    if !data.contains_key("name") || data.get("name").unwrap().is_empty() {
        return Err(Box::new(DataLoadError::NotFound(format!("No name provided for key: {}", key))));
    }

    if data.get("version").map(|s| s.parse::<i32>().is_err()).unwrap_or(false) {
        return Err(Box::new(DataLoadError::ServiceFailure("Version must be an integer".to_string())));
    }

    Ok(())
}

fn main() {
    let mut data = HashMap::new();
    data.insert("name".to_string(), "TestItem".to_string());
    data.insert("version".to_string(), "1".to_string());

    match process_data("item123", &data) {
        Ok(_) => println!("Successfully processed data."),
        Err(e) => println!("Failed to process data: {}", e),
    }

    let mut bad_data = HashMap::new();
    bad_data.insert("name".to_string(), "".to_string());
    match process_data("item456", &bad_data) {
        Ok(_) => println!("Successfully processed data."),
        Err(e) => println!("Failed to process data: {}", e),
    }
}

use std::fmt::{self, Display};
use std::io;
use std::path::Path;

#[derive(Debug)]
enum ConfigError {
    Io(io::Error),
    InvalidFormat(&'static str),
}

impl From<io::Error> for ConfigError {
    fn from(err: io::Error) -> Self {
        ConfigError::Io(err)
    }
}

impl Display for ConfigError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            ConfigError::Io(err) => write!(f, "File system error: {}", err),
            ConfigError::InvalidFormat(msg) => write!(f, "Bad data format: {}", msg),
        }
    }
}

impl std::error::Error for ConfigError {}

fn process_config_file(path: &Path) -> Result<Vec<String>, ConfigError> {
    let contents = std::fs::read_to_string(path)?;
    let mut filtered_lines = Vec::new();

    for line in contents.lines() {
        if !line.contains("deprecated") {
            filtered_lines.push(String::from(line));
        }
    }

    Ok(filtered_lines)
}

fn main() -> Result<(), ConfigError> {
    let dummy_path = Path::new("test_config.txt");
    if !dummy_path.exists() {
        std::fs::write(dummy_path, "setting1=valuendeprecated: old keynsetting2=okn")?;
    }

    match process_config_file(dummy_path) {
        Ok(lines) => {
            println!("Successfully processed {} lines:", lines.len());
            for line in lines {
                println!("{}", line);
            }
        }
        Err(e) => {
            eprintln!("Error processing configuration: {}", e);
        }
    }

    std::fs::remove_file(dummy_path).ok();
    Ok(())
}
